from __future__ import annotations

from collections.abc import Iterable

from ci_app.service import run_checks


PACKAGE_NAME = "payments_gate_legacy"


def expected_package_name() -> str:
    return PACKAGE_NAME


def workflow_command(package_name: str | None = None) -> str:
    package = package_name or expected_package_name()
    return f"python scripts/run_ci.py --package {package}"


def dispatch_job_ids(labels: Iterable[str] | None = None) -> list[str]:
    active_labels = list(run_checks() if labels is None else labels)
    package_slug = expected_package_name().replace("_", "-")
    return [
        f"{package_slug}-{label.strip().lower().replace('_', '-').replace('/', '-')}"
        for label in active_labels
    ]


def render_summary(labels: Iterable[str] | None = None) -> str:
    return " | ".join(dispatch_job_ids(labels))

from __future__ import annotations

from ci_app.policy import active_labels


def run_checks() -> list[str]:
    return active_labels()


def gate_snapshot() -> dict[str, list[str]]:
    required = active_labels()
    optional = [label for label in active_labels(include_optional=True) if label not in required]
    return {"required": required, "optional": optional}

from __future__ import annotations

from ci_app.cli import main
from ci_app.service import gate_snapshot, run_checks


def test_service_contract_still_returns_required_labels() -> None:
    assert run_checks() == ["queue-check", "ledger-check"]

    output = main()
    assert "queue-check" in output
    assert "ledger-check" in output


def test_gate_snapshot_keeps_receipt_audit_optional() -> None:
    assert gate_snapshot() == {
        "required": ["queue-check", "ledger-check"],
        "optional": ["receipt__audit"],
    }

